// functions/index.ts — the entrypoint for your project's backend.
//
// Temporary admin proxy for Render API operations (repo repoint + deploy).
// Gated by ADMIN_TOKEN. Remove /render/* routes after the migration is done.

interface Env {
  RENDER_API_KEY?: string;
}

const ADMIN_TOKEN = "ivx-rp-7f3a9c1e5b2d4086";
const RENDER_API = "https://api.render.com/v1";

export default {
  async fetch(request: Request, env: Env): Promise<Response> {
    const url = new URL(request.url);

    if (url.pathname === "/ping") {
      return Response.json({ ok: true, now: new Date().toISOString() });
    }

    if (url.pathname === "/render/proxy" && request.method === "POST") {
      const auth = request.headers.get("X-Admin-Token");
      if (auth !== ADMIN_TOKEN) {
        return Response.json({ error: "forbidden" }, { status: 403 });
      }
      const key = env.RENDER_API_KEY;
      if (!key) {
        return Response.json(
          { error: "RENDER_API_KEY not present in worker env" },
          { status: 500 },
        );
      }
      let payload: { method?: string; path?: string; body?: unknown };
      try {
        payload = (await request.json()) as {
          method?: string;
          path?: string;
          body?: unknown;
        };
      } catch {
        return Response.json({ error: "invalid json" }, { status: 400 });
      }
      const method = (payload.method ?? "GET").toUpperCase();
      const path = payload.path ?? "/services";
      if (!path.startsWith("/")) {
        return Response.json({ error: "path must start with /" }, { status: 400 });
      }
      const init: RequestInit = {
        method,
        headers: {
          Authorization: `Bearer ${key}`,
          Accept: "application/json",
          "Content-Type": "application/json",
        },
      };
      if (payload.body !== undefined && method !== "GET") {
        init.body = JSON.stringify(payload.body);
      }
      const upstream = await fetch(`${RENDER_API}${path}`, init);
      const text = await upstream.text();
      console.log("render-proxy", method, path, upstream.status);
      return new Response(text, {
        status: upstream.status,
        headers: { "Content-Type": "application/json" },
      });
    }

    return Response.json({ ok: true, hello: "world" });
  },
};

